INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-416.5, 1, 20047002, "カリン", 0.0, 2, "2030/01/01 14:59:59", 53, "ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, 190801, 20047, "2023/11/16 15:00:00", 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-416.5, 1, 20047003, "カリン", 0.0, 3, "2030/01/01 14:59:59", 54, "受け取ることができる\n報酬があるようです\n確認してみてください", 2.801, 190801, 20047, "2023/11/16 15:00:00", 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-416.5, 2, 20047004, "カリン", 0.0, 4, "2030/01/01 14:59:59", 54, "報酬がもらえますよ！\nチェックしてみてください", 0.0, 190801, 20047, "2023/11/16 15:00:00", 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-416.5, 1, 20047005, "カリン", 0.0, 5, "2030/01/01 14:59:59", 57, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 0.0, 190801, 20047, "2023/11/16 15:00:00", 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-363.0, 1, 20047006, "カリン", 0.0, 1, "2030/01/01 14:59:59", 55, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 5.506, 190801, 20047, "2023/11/16 15:00:00", 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-363.0, 2, 20047007, "カリン", 0.0, 2, "2030/01/01 14:59:59", 55, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", 1.216, 190801, 20047, "2023/11/16 15:00:00", 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-363.0, 2, 20047008, "カリン", 0.0, 3, "2030/01/01 14:59:59", 56, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 1.539, 190801, 20047, "2023/11/16 15:00:00", 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-363.0, 2, 20047009, "カリン", 0.0, 4, "2030/01/01 14:59:59", 56, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 1.875, 190801, 20047, "2023/11/16 15:00:00", 1);
