INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-416.5, 1, 20078002, "カリン", 0.0, 2, "2030/01/01 14:59:59", 53, "ミッションをクリアして、\n報酬をゲットしましょう！", 3.099, 190805, 20078, "2026/06/16 15:00:00", 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-416.5, 1, 20078003, "カリン", 0.0, 3, "2030/01/01 14:59:59", 54, "受け取ることができる\n報酬があるようです\n確認してみてください", 2.801, 190805, 20078, "2026/06/16 15:00:00", 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-416.5, 2, 20078004, "カリン", 0.0, 4, "2030/01/01 14:59:59", 54, "報酬がもらえますよ！\nチェックしてみてください", 0.0, 190805, 20078, "2026/06/16 15:00:00", 2);
