INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-363.0, 1, 20078006, "カリン", 0.0, 1, "2030/01/01 14:59:59", 55, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 5.506, 190805, 20078, "2026/06/16 15:00:00", 2);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-363.0, 2, 20078007, "カリン", 0.0, 2, "2030/01/01 14:59:59", 55, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", 1.216, 190805, 20078, "2026/06/16 15:00:00", 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-363.0, 2, 20078008, "カリン", 0.0, 3, "2030/01/01 14:59:59", 56, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 1.539, 190805, 20078, "2026/06/16 15:00:00", 1);
INSERT INTO `v1_409156a8daa0060ac935dd09b63850bbca5190b117f5332dd3b2bc027206c4ee` VALUES (-363.0, 2, 20078009, "カリン", 0.0, 4, "2030/01/01 14:59:59", 56, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 1.875, 190805, 20078, "2026/06/16 15:00:00", 1);
